interface EditEventModalProps {
    isOpen: boolean;
    event: MedicalEvent | null;
    onClose: () => void;
    onSave: (event: MedicalEvent) => void;
}

const EditEventModal: React.FC<EditEventModalProps> = ({ isOpen, event, onClose, onSave }) => {
    const [formData, setFormData] = useState<MedicalEvent | null>(null);

    useEffect(() => {
        if (event) {
             // Data migration for old infection events
            if (event.type === MedicalEventType.OPPORTUNISTIC_INFECTION && event.details.โรค && !event.details.infections) {
                const migratedEvent = { ...event, details: { ...event.details, infections: [event.details.โรค] } };
                setFormData({ ...migratedEvent, date: toLocalISOString(migratedEvent.date) });
            } else {
                setFormData({ ...event, date: toLocalISOString(event.date) });
            }
        }
    }, [event]);

    if (!isOpen || !event || !formData) return null;

    const handleDetailChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
        const { name, value, type } = e.target;
        const newDetails = { ...formData.details };

        if (e.currentTarget.dataset.group === 'infections') {
            const { checked } = e.currentTarget as HTMLInputElement;
            const currentInfections = newDetails.infections || [];
            let newInfections = checked
                ? [...currentInfections, name]
                : currentInfections.filter(i => i !== name);

            // Clean up TB subtypes if parent Tuberculosis is unchecked
            if (name === 'Tuberculosis' && !checked) {
                newInfections = newInfections.filter(i => !TB_TYPES.includes(i));
            }

            newDetails.infections = newInfections;
        } else if (type === 'checkbox') {
            const { checked } = e.target as HTMLInputElement;
            newDetails[name] = checked;
            if (name === 'อื่นๆ' && !checked) {
                delete newDetails['การติดเชื้ออื่นๆ'];
            }
        } else {
            newDetails[name] = value;
        }
        setFormData(prev => prev ? { ...prev, details: newDetails } : null);
    };

    const handleArvChange = (name: string, value: string) => {
        const newDetails = { ...formData.details };
        newDetails[name] = value;
        setFormData(prev => prev ? { ...prev, details: newDetails } : null);
    };

    const handleDateChange = (e: { target: { value: string } }) => {
        setFormData(prev => prev ? { ...prev, date: e.target.value } : null);
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (formData) {
            const cleanedData = { ...formData };
            if (cleanedData.type === MedicalEventType.OPPORTUNISTIC_INFECTION) {
                delete cleanedData.details['โรค']; // remove old key on save
            }
            onSave(cleanedData);
        }
    };

    const eventTypeInfo = eventTypes.find(et => et.type === event.type);

    return (
        <div className="fixed inset-0 bg-black bg-opacity-50 z-50 flex justify-center items-center p-4" onClick={onClose}>
            <div className="bg-white rounded-lg shadow-xl w-full max-w-2xl max-h-[90vh] flex flex-col" onClick={e => e.stopPropagation()}>
                <div className="p-6 border-b flex justify-between items-center">
                    <h3 className="text-xl font-semibold text-gray-800">แก้ไขเหตุการณ์: {eventTypeInfo?.label}</h3>
                    <button onClick={onClose} className="text-gray-400 hover:text-gray-600">&times;</button>
                </div>
                <form onSubmit={handleSubmit} className="overflow-y-auto">
                    <div className="p-6 space-y-4">
                        <div>
                            <label htmlFor="eventDateEdit" className={labelClass}>ลงวันที่</label>
                            <DateInput id="eventDateEdit" value={formData.date} onChange={handleDateChange} />
                        </div>
                        {renderEventDetailForm(event.type, formData.details, handleDetailChange, handleArvChange)}
                    </div>
                    <div className="p-6 border-t flex justify-end gap-x-3 bg-gray-50 rounded-b-lg sticky bottom-0">
                        <button onClick={onClose} type="button" className="px-6 py-2 text-sm font-medium text-gray-700 bg-white border border-gray-300 rounded-lg hover:bg-gray-50">
                           ยกเลิก
                       </button>
                       <button type="submit" className="px-6 py-2 text-sm font-medium text-white bg-emerald-600 rounded-lg hover:bg-emerald-700">
                           บันทึกการแก้ไข
                       </button>
                    </div>
                </form>
            </div>
        </div>
    );
};

interface AddEventFormProps {
    onSave: (event: Omit<MedicalEvent, 'id'>) => void;
    patientHistory: MedicalEvent[];
    onEditDiagnosis: (event: MedicalEvent) => void;
    forceEventType?: MedicalEventType;
    formTitle?: string;
    onCancel?: () => void;
}

const AddEventForm: React.FC<AddEventFormProps> = ({ onSave, patientHistory, onEditDiagnosis, forceEventType, formTitle, onCancel }) => {
    const [date, setDate] = useState(toLocalISOString(new Date()));
    const [eventType, setEventType] = useState<MedicalEventType | null>(null);
    const [details, setDetails] = useState<Record<string, any>>({});

    useEffect(() => {
        if (forceEventType) {
            setEventType(forceEventType);
        }
    }, [forceEventType]);

    const existingDiagnosis = patientHistory.find(e => e.type === MedicalEventType.DIAGNOSIS);

    const resetForm = () => {
        setDate(toLocalISOString(new Date()));
        setEventType(forceEventType || null);
        setDetails({});
        if (onCancel) {
            onCancel();
        }
    };

    const handleEventTypeSelect = (type: MedicalEventType) => {
        if (type === MedicalEventType.DIAGNOSIS && existingDiagnosis) {
            onEditDiagnosis(existingDiagnosis);
            return;
        }

        // Removed setDate(toLocalISOString(new Date())) to keep user selection
        setEventType(type);

        let newDetails: Record<string, any> = {};

        // Auto-populate based on event type
        if (type === MedicalEventType.ART_CHANGE) {
             const currentRegimen = getCurrentArv(patientHistory);
             if (currentRegimen && currentRegimen !== '-' && currentRegimen !== 'N/A') {
                 newDetails['จาก'] = currentRegimen;
             }
        }

        setDetails(newDetails);
    };

    const handleDetailChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
        const { name, value, type } = e.target;
        const isCheckbox = type === 'checkbox';

        if (e.currentTarget.dataset.group === 'infections') {
            const { checked } = e.currentTarget as HTMLInputElement;
            setDetails(prev => {
                const currentInfections = prev.infections || [];
                let newInfections = checked
                    ? [...currentInfections, name]
                    : currentInfections.filter(i => i !== name);

                // Clean up TB subtypes if parent Tuberculosis is unchecked
                if (name === 'Tuberculosis' && !checked) {
                    newInfections = newInfections.filter(i => !TB_TYPES.includes(i));
                }

                return { ...prev, infections: newInfections };
            });
            return;
        }

        if (isCheckbox) {
            const { checked } = e.target as HTMLInputElement;
             setDetails(prev => ({...prev, [name]: checked}));
             if (name === 'อื่นๆ' && !checked) {
                setDetails(prev => {
                    const newDetails = {...prev};
                    delete newDetails['การติดเชื้ออื่นๆ'];
                    return newDetails;
                });
            }
        } else {
             setDetails(prev => ({...prev, [name]: value}));
        }
    };

    const handleArvChange = (name: string, value: string) => {
        setDetails(prev => ({ ...prev, [name]: value }));
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (!eventType || !date) return;

        const eventTypeInfo = eventTypes.find(et => et.type === eventType);

         const newEvent: Omit<MedicalEvent, 'id'> = {
            date,
            type: eventType,
            title: eventTypeInfo?.label || 'Unknown Event',
            details,
        };
        onSave(newEvent);
        resetForm();
    };

    return (
        <form onSubmit={handleSubmit} className="bg-white p-6 rounded-lg shadow-sm border border-emerald-200">
            <h3 className="text-xl font-semibold text-gray-800 mb-6">{formTitle || 'เพิ่มเหตุการณ์ใหม่'}</h3>
            <div className="space-y-6">
                <div>
                    <label htmlFor="eventDate" className={labelClass}>ลงวันที่</label>
                    <DateInput id="eventDate" value={date} onChange={(e) => setDate(e.target.value)} />
                </div>

                {!forceEventType && (
                    <div>
                        <label className={labelClass}>เลือกเหตุการณ์</label>
                        <div className="grid grid-cols-2 md:grid-cols-4 gap-2 mt-2">
                            {eventTypes.map(et => {
                                const isDiagnosisAndExists = et.type === MedicalEventType.DIAGNOSIS && !!existingDiagnosis;
                                return (
                                    <button
                                        key={et.type}
                                        type="button"
                                        onClick={() => handleEventTypeSelect(et.type)}
                                        className={`relative flex flex-col items-center justify-center p-3 border rounded-lg hover:shadow-md transition-all text-center ${eventType === et.type ? 'ring-2 ring-emerald-500 bg-emerald-50' : 'bg-white'} ${isDiagnosisAndExists ? 'border-amber-400 bg-amber-50' : ''}`}
                                    >
                                        {isDiagnosisAndExists && (
                                            <span className="absolute -top-2 -right-2 text-xs bg-amber-500 text-white px-1.5 py-0.5 rounded-full text-[10px] font-bold shadow">EDIT</span>
                                         )}
                                        <div className={`w-10 h-10 rounded-full flex items-center justify-center ${et.color}`}>
                                            {et.icon}
                                        </div>
                                        <span className="mt-2 text-xs font-medium text-gray-700">{et.label}</span>
                                    </button>
                                );
                            })}
                        </div>
                    </div>
                )}

                 {eventType && (
                    <div className={!forceEventType ? "pt-6 border-t" : ""}>
                        <h4 className="text-lg font-semibold text-gray-800 mb-4">
                            {eventTypes.find(e => e.type === eventType)?.label}
                        </h4>
                        {renderEventDetailForm(eventType, details, handleDetailChange, handleArvChange)}
                         <div className="flex justify-end gap-x-3 mt-6">
                            <button onClick={resetForm} type="button" className="px-6 py-2 text-sm font-medium text-gray-700 bg-white border border-gray-300 rounded-lg hover:bg-gray-50">
                               ยกเลิก
                           </button>
                           <button type="submit" className="px-6 py-2 text-sm font-medium text-white bg-emerald-600 rounded-lg hover:bg-emerald-700">
                               บันทึกเหตุการณ์
                           </button>
                        </div>
                    </div>
                )}
            </div>
        </form>
    );
};


interface HivTreatmentTabProps {
    patient: Patient;
    onSaveEvent: (event: Omit<MedicalEvent, 'id'> | MedicalEvent) => void;
    onDeleteEvent: (eventId: string) => void;
}

export const HivTreatmentTab: React.FC<HivTreatmentTabProps> = ({ patient, onSaveEvent, onDeleteEvent }) => {
    const [editingEvent, setEditingEvent] = useState<MedicalEvent | null>(null);
    const [isDiagnosing, setIsDiagnosing] = useState(false);

    const hasDiagnosis = patient.medicalHistory.some(e => e.type === MedicalEventType.DIAGNOSIS);

    const handleSaveDiagnosis = (eventData: Omit<MedicalEvent, 'id'>) => {
        onSaveEvent(eventData);
        setIsDiagnosing(false);
    };

    if (!hasDiagnosis) {
        if (isDiagnosing) {
            return (
                <AddEventForm 
                    onSave={handleSaveDiagnosis} 
                    patientHistory={patient.medicalHistory} 
                    onEditDiagnosis={() => {}} // This won't be called as there's no diagnosis to edit
                    forceEventType={MedicalEventType.DIAGNOSIS}
                    formTitle="บันทึกการวินิจฉัย HIV"
                    onCancel={() => setIsDiagnosing(false)}
                />
            );
        }

        return (
            <div className="bg-white p-8 rounded-lg shadow-sm text-center border border-gray-200">
                <h3 className="text-xl font-semibold text-gray-800">ผู้ป่วยรายนี้ยังไม่ได้รับการวินิจฉัยว่าเป็น HIV</h3>
                <p className="text-gray-600 mt-2 mb-6">กดปุ่มเพื่อเปิดการวินิจฉัย HIV</p>
                <button 
                    onClick={() => setIsDiagnosing(true)} 
                    className="inline-flex items-center px-6 py-2 text-sm font-medium text-white bg-emerald-600 rounded-lg hover:bg-emerald-700"
                >
                    <PlusIcon className="mr-2 h-4 w-4" />
                    เปิดการวินิจฉัย HIV
                </button>
            </div>
        );
    }

    const virtualEvents: MedicalEvent[] = [];

    // HBV Events
    if (patient.hbvInfo) {
        patient.hbvInfo.hbsAgTests?.forEach(test => {
            virtualEvents.push({
                id: `hbv-hbsag-${test.id}`,
                type: MedicalEventType.OTHER,
                date: test.date,
                title: 'ผลตรวจ HBsAg',
                details: { 'ผล': test.result }
            });
        });
        patient.hbvInfo.viralLoads?.forEach(test => {
            virtualEvents.push({
                id: `hbv-vl-${test.id}`,
                type: MedicalEventType.OTHER,
                date: test.date,
                title: 'ผลตรวจ HBV Viral Load',
                details: { 'ผล': test.result }
            });
        });
        patient.hbvInfo.ultrasounds?.forEach(test => {
            virtualEvents.push({
                id: `hbv-us-${test.id}`,
                type: MedicalEventType.OTHER,
                date: test.date,
                title: 'ผลตรวจ Ultrasound ตับ',
                details: { 'ผล': test.result }
            });
        });
        patient.hbvInfo.ctScans?.forEach(test => {
            virtualEvents.push({
                id: `hbv-ct-${test.id}`,
                type: MedicalEventType.OTHER,
                date: test.date,
                title: 'ผลตรวจ CT Upper Abdomen',
                details: { 'ผล': test.result }
            });
        });
    }

    // HCV Events
    if (patient.hcvInfo) {
        patient.hcvInfo.hcvTests?.forEach(test => {
            virtualEvents.push({
                id: `hcv-test-${test.id}`,
                type: MedicalEventType.OTHER,
                date: test.date,
                title: `ผลตรวจ ${test.type}`,
                details: { 'ผล': test.result }
            });
        });
        patient.hcvInfo.preTreatmentVls?.forEach(test => {
            virtualEvents.push({
                id: `hcv-prevl-${test.id}`,
                type: MedicalEventType.OTHER,
                date: test.date,
                title: 'ผลตรวจ HCV Viral Load (ก่อนรักษา)',
                details: { 'ผล': test.result }
            });
        });
        patient.hcvInfo.treatments?.forEach(treatment => {
            virtualEvents.push({
                id: `hcv-treat-${treatment.id}`,
                type: MedicalEventType.ART_START,
                date: treatment.date,
                title: 'เริ่มการรักษา HCV',
                details: { 'สูตรยา': treatment.regimen }
            });
        });
        patient.hcvInfo.postTreatmentVls?.forEach(test => {
            virtualEvents.push({
                id: `hcv-postvl-${test.id}`,
                type: MedicalEventType.OTHER,
                date: test.date,
                title: 'ผลตรวจ HCV Viral Load (หลังรักษา)',
                details: { 'ผล': test.result }
            });
        });
    }

    const combinedHistory = [...patient.medicalHistory, ...virtualEvents];
    const sortedHistory = combinedHistory.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

    const latestTptEvent = patient.medicalHistory
        .filter(e => e.type === MedicalEventType.PROPHYLAXIS && e.details.TPT)
        .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime())[0];


    const handleEditEvent = (event: MedicalEvent) => {
        setEditingEvent(event);
    };

    const handleSaveModal = (updatedEvent: MedicalEvent) => {
        if (updatedEvent.id.startsWith('hbv-') || updatedEvent.id.startsWith('hcv-')) {
            setEditingEvent(null);
            return; // Do not save virtual events
        }
        onSaveEvent(updatedEvent);
        setEditingEvent(null);
    }

    const renderTimelineEventDetails = (event: MedicalEvent) => {
        if (event.type === MedicalEventType.OPPORTUNISTIC_INFECTION) {
            const infectionsList = event.details.infections || [];
            const otherInfection = event.details['การติดเชื้ออื่นๆ'] || '';
            let fullInfectionList = [...infectionsList];
            if (otherInfection) fullInfectionList.push(otherInfection);

            // Handle old data format for display
            if (fullInfectionList.length === 0 && event.details.โรค) {
                fullInfectionList.push(event.details.โรค);
            }

            if (fullInfectionList.length > 0) {
                 return <p className="whitespace-pre-line"><span className="font-medium text-gray-800">การติดเชื้อ:</span> {fullInfectionList.join(', ')}</p>;
            }
        }

        // Default rendering for other event types
        return Object.entries(event.details).map(([key, value]) => {
            if (key === 'infections' || key === 'การติดเชื้ออื่นๆ' || key === 'อื่นๆ') return null; // Already handled for OI
            if (value === true) {
                return <p key={key}><span className="font-medium text-gray-800">{key}</span></p>;
            }
            if (value) {
                 return <p key={key} className="whitespace-pre-line"><span className="font-medium text-gray-800">{key}:</span> {String(value)}</p>;
            }
            return null;
        });
    }


    return (
        <div>
            <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
                <InfoCard title="วันที่ทราบผลตรวจครั้งแรก" value={getFirstEventDate(patient.medicalHistory, MedicalEventType.DIAGNOSIS)} />
                <InfoCard title="วันที่ได้รับยา ARV ครั้งแรก" value={getFirstEventDate(patient.medicalHistory, MedicalEventType.ART_START)} />
                <InfoCard title="สูตรยา ARV ปัจจุบัน" value={getCurrentArv(patient.medicalHistory)} />
                <div className="bg-white p-6 rounded-lg shadow-sm">
                    <p className="text-sm text-gray-500">TPT</p>
                    <p className="text-2xl font-bold text-green-600 mt-2 truncate" title={latestTptEvent ? `${latestTptEvent.details['สูตร TPT']} (${formatThaiDateBE(latestTptEvent.date)})` : '-'}>
                        {latestTptEvent
                            ? <span className="whitespace-nowrap">{latestTptEvent.details['สูตร TPT']} ({formatThaiDateBE(latestTptEvent.date)})</span>
                            : '-'}
                    </p>
                </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mt-8">
                {/* Left Column: Add Event Form */}
                <div>
                     <AddEventForm 
                        onSave={onSaveEvent} 
                        patientHistory={patient.medicalHistory} 
                        onEditDiagnosis={handleEditEvent}
                    />
                </div>

                {/* Right Column: Timeline */}
                <div className="bg-white p-6 rounded-lg shadow-sm border">
                     <h3 className="text-xl font-semibold text-gray-800 mb-6">ประวัติการรักษา (เรียงจากล่าสุด)</h3>

                    {sortedHistory.length > 0 ? (
                        <div className="relative pl-5 max-h-[800px] overflow-y-auto pr-2">
                            <div className="absolute left-5 top-0 h-full w-0.5 bg-gray-200" aria-hidden="true"></div>
                            <div className="space-y-8">
                                {sortedHistory.map((event) => {
                                    const isVirtualEvent = event.id.startsWith('hbv-') || event.id.startsWith('hcv-');
                                    return (
                                        <div key={event.id} className="relative flex items-start group">
                                            <div className="absolute top-0 -left-5 z-10">
                                                 <TimelineIcon type={event.type} />
                                            </div>
                                            <div className="ml-8 flex-grow bg-white p-4 rounded-lg border border-gray-200">
                                                <div className="flex justify-between items-center">
                                                    <h3 className="font-semibold text-gray-900 text-md">{event.title}</h3>
                                                    <div className="flex items-center text-sm text-gray-500">
                                                        <span>{formatThaiDateBE(event.date)}</span>
                                                        {/* Allow deleting everything, including virtual events */}
                                                        {!isVirtualEvent && (
                                                            <button 
                                                                type="button"
                                                                onClick={() => handleEditEvent(event)} 
                                                                className="ml-3 p-1.5 text-gray-400 hover:text-emerald-600 hover:bg-emerald-50 rounded-full transition-colors" 
                                                                aria-label={`Edit event ${event.title}`}
                                                            >
                                                                <EditIcon />
                                                            </button>
                                                        )}
                                                        <button 
                                                            type="button"
                                                            onClick={(e) => { e.preventDefault(); e.stopPropagation(); onDeleteEvent(event.id); }} 
                                                            className="ml-1 p-1.5 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-full transition-colors relative z-20"
                                                            aria-label={`Delete event ${event.title}`}
                                                            title="ลบข้อมูล"
                                                        >
                                                            <TrashIcon className="h-4 w-4 pointer-events-none" />
                                                        </button>
                                                    </div>
                                                </div>
                                                <div className="text-sm text-gray-600 mt-2 space-y-1">
                                                   {renderTimelineEventDetails(event)}
                                                </div>
                                            </div>
                                        </div>
                                    )
                                })}
                            </div>
                        </div>
                    ) : (
                        <div className="text-center py-10">
                            <p className="text-gray-500">ยังไม่มีประวัติการรักษา</p>
                        </div>
                    )}
                </div>
            </div>

            <EditEventModal
                isOpen={!!editingEvent}
                event={editingEvent}
                onClose={() => setEditingEvent(null)}
                onSave={handleSaveModal}
            />
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { Patient, StdRecord } from '../../types';
import { EditIcon, StdIcon, TrashIcon } from '../icons';
import { formatThaiDateBE, inputClass, labelClass, toLocalISOString } from '../utils';
import { DateInput } from '../DateInput';

interface StdTabProps {
    patient: Patient;
    onUpdatePatient: (patient: Patient) => void;
}

// 1. Standalone STDs
const STD_STANDALONE = [
    'Gonorrhea', 
    'Non-Gonorrhea', 
    'PID', 
    'Trichomoniasis', 
    'HSV', 
    'Chancroid', 
    'LGV', 
    'Donovanosis', 
    'HPV',
    'Monkey Pox'
];

// 2. Syphilis Options (Multiple Choice)
const SYPHILIS_OPTIONS = [
    'Primary Syphilis',
    'Secondary Syphilis',
    'Early Syphilis',
    'Late Latent Syphilis',
    'Neuro Syphilis',
    'Cardiovascular Syphilis',
    'Congenital Syphilis',
    'Syphilis (ไม่ทราบ)'
];

// 3. Contact STD Options (Multiple Choice)
const CONTACT_STD_OPTIONS = [
    'Contact GC',
    'Contact Non-Gonorrhea',
    'Contact Syphilis',
    'Contact PID',
    'Contact Trichomoniasis',
    'Contact Chancroid',
    'Contact LGV',
    'Contact Other'
];

interface StdSelectionFormProps {
    selectedDiseases: Set<string>;
    onToggleDisease: (disease: string, isChecked: boolean) => void;

    // Group visibility states
    isSyphilisGroupChecked: boolean;
    onToggleSyphilisGroup: (isChecked: boolean) => void;

    isContactGroupChecked: boolean;
    onToggleContactGroup: (isChecked: boolean) => void;

    // Other State
    isOtherChecked: boolean;
    otherText: string;
    onToggleOther: (isChecked: boolean) => void;
    onOtherTextChange: (val: string) => void;
}

const StdSelectionForm: React.FC<StdSelectionFormProps> = ({
    selectedDiseases, onToggleDisease,
    isSyphilisGroupChecked, onToggleSyphilisGroup,
    isContactGroupChecked, onToggleContactGroup,
    isOtherChecked, otherText, onToggleOther, onOtherTextChange
}) => {
    return (
        <div className="space-y-4">
            {/* Group 1: Standalone Diseases */}
            <div className="grid grid-cols-2 gap-x-4 gap-y-2">
                {STD_STANDALONE.map(disease => (
                    <div key={disease} className="flex items-center">
                        <input
                            type="checkbox"
                            id={`std-${disease}`}
                            checked={selectedDiseases.has(disease)}
                            onChange={(e) => onToggleDisease(disease, e.target.checked)}
                            className="h-4 w-4 rounded border-gray-300 text-emerald-600 focus:ring-emerald-500"
                        />
                        <label htmlFor={`std-${disease}`} className="ml-2 text-sm text-gray-700">{disease}</label>
                    </div>
                ))}
            </div>

            <div className="border-t border-gray-100 my-2"></div>

            {/* Group 2: Syphilis Hierarchy */}
            <div className="bg-orange-50 p-3 rounded-md border border-orange-100">
                <div className="flex items-center mb-2">
                    <input
                        type="checkbox"
                        id="std-syphilis-group"
                        checked={isSyphilisGroupChecked}
                        onChange={(e) => onToggleSyphilisGroup(e.target.checked)}
                        className="h-4 w-4 rounded border-gray-300 text-orange-600 focus:ring-orange-500"
                    />
                    <label htmlFor="std-syphilis-group" className="ml-2 text-sm font-bold text-orange-800">Syphilis</label>
                </div>
                {isSyphilisGroupChecked && (
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-2 pl-6">
                        {SYPHILIS_OPTIONS.map(opt => (
                            <div key={opt} className="flex items-center">
                                <input
                                    type="checkbox"
                                    id={`syphilis-${opt}`}
                                    checked={selectedDiseases.has(opt)}
                                    onChange={(e) => onToggleDisease(opt, e.target.checked)}
                                    className="h-4 w-4 rounded border-gray-300 text-orange-600 focus:ring-orange-500"
                                />
                                <label htmlFor={`syphilis-${opt}`} className="ml-2 text-sm text-gray-700">{opt}</label>
                            </div>
                        ))}
                    </div>
                )}
            </div>

            {/* Group 3: Contact STD Hierarchy */}
            <div className="bg-blue-50 p-3 rounded-md border border-blue-100">
                <div className="flex items-center mb-2">
                    <input
                        type="checkbox"
                        id="std-contact-group"
                        checked={isContactGroupChecked}
                        onChange={(e) => onToggleContactGroup(e.target.checked)}
                        className="h-4 w-4 rounded border-gray-300 text-blue-600 focus:ring-blue-500"
                    />
                    <label htmlFor="std-contact-group" className="ml-2 text-sm font-bold text-blue-800">Contact STD</label>
                </div>
                {isContactGroupChecked && (
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-2 pl-6">
                        {CONTACT_STD_OPTIONS.map(opt => (
                            <div key={opt} className="flex items-center">
                                <input
                                    type="checkbox"
                                    id={`contact-${opt}`}
                                    checked={selectedDiseases.has(opt)}
                                    onChange={(e) => onToggleDisease(opt, e.target.checked)}
                                    className="h-4 w-4 rounded border-gray-300 text-blue-600 focus:ring-blue-500"
                                />
                                <label htmlFor={`contact-${opt}`} className="ml-2 text-sm text-gray-700">{opt}</label>
                            </div>
                        ))}
                    </div>
                )}
            </div>

            <div className="border-t border-gray-100 my-2"></div>

            {/* Group 4: Other */}
            <div>
                <div className="flex items-center">
                        <input type="checkbox" id="std-other-check" checked={isOtherChecked} onChange={e => onToggleOther(e.target.checked)} className="h-4 w-4 rounded border-gray-300 text-emerald-600 focus:ring-emerald-500" />
                        <label htmlFor="std-other-check" className="ml-2 text-sm font-semibold text-gray-800">อื่นๆ</label>
                </div>
                {isOtherChecked && (
                    <div className="mt-2 pl-6">
                        <label htmlFor="std-other-text" className={labelClass}>ระบุโรคอื่นๆ</label>
                        <input type="text" id="std-other-text" value={otherText} onChange={e => onOtherTextChange(e.target.value)} className={inputClass} />
                    </div>
                )}
            </div>
        </div>
    );
}


const EditStdModal: React.FC<{
    isOpen: boolean;
    record: StdRecord | null;
    onClose: () => void;
    onSave: (record: StdRecord) => void;
}> = ({ isOpen, record, onClose, onSave }) => {
    const [date, setDate] = useState('');

    // Form States
    const [selectedDiseases, setSelectedDiseases] = useState<Set<string>>(new Set());

    const [isSyphilisGroupChecked, setIsSyphilisGroupChecked] = useState(false);
    const [isContactGroupChecked, setIsContactGroupChecked] = useState(false);

    const [isOtherChecked, setIsOtherChecked] = useState(false);
    const [otherText, setOtherText] = useState('');

    useEffect(() => {
        if (record) {
            setDate(record.date);
            const newSelected = new Set<string>();
            let foundOtherText = '';
            const otherDiseases: string[] = [];

            let foundSyphilisGroup = false;
            let foundContactGroup = false;

            record.diseases.forEach(d => {
                if (STD_STANDALONE.includes(d)) {
                    newSelected.add(d);
                } else if (SYPHILIS_OPTIONS.includes(d)) {
                    foundSyphilisGroup = true;
                    newSelected.add(d);
                } else if (CONTACT_STD_OPTIONS.includes(d)) {
                    foundContactGroup = true;
                    newSelected.add(d);
                } else {
                    // Assuming anything else is 'Other'
                    otherDiseases.push(d);
                }
            });

            setSelectedDiseases(newSelected);

            setIsSyphilisGroupChecked(foundSyphilisGroup);
            setIsContactGroupChecked(foundContactGroup);

            if (otherDiseases.length > 0) {
                setIsOtherChecked(true);
                setOtherText(otherDiseases.join(', '));
            } else {
                setIsOtherChecked(false);
                setOtherText('');
            }
        }
    }, [record]);

    if (!isOpen || !record) return null;

    const handleToggleDisease = (disease: string, checked: boolean) => {
        setSelectedDiseases(prev => {
            const next = new Set(prev);
            if (checked) next.add(disease);
            else next.delete(disease);
            return next;
        });
    };

    const handleToggleSyphilisGroup = (checked: boolean) => {
        setIsSyphilisGroupChecked(checked);
        if (!checked) {
            // Remove all Syphilis options from selection
            setSelectedDiseases(prev => {
                const next = new Set(prev);
                SYPHILIS_OPTIONS.forEach(opt => next.delete(opt));
                return next;
            });
        }
    };

    const handleToggleContactGroup = (checked: boolean) => {
        setIsContactGroupChecked(checked);
        if (!checked) {
             // Remove all Contact options from selection
            setSelectedDiseases(prev => {
                const next = new Set(prev);
                CONTACT_STD_OPTIONS.forEach(opt => next.delete(opt));
                return next;
            });
        }
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        const finalDiseases = [...selectedDiseases];

        // Validation: If Group Checked, must have sub-selection?
        // Let's enforce strictly to prevent empty groups
        if (isSyphilisGroupChecked) {
             const hasSyphilisSelection = SYPHILIS_OPTIONS.some(opt => selectedDiseases.has(opt));
             if (!hasSyphilisSelection) {
                 alert('กรุณาเลือกประเภทของ Syphilis อย่างน้อย 1 รายการ');
                 return;
             }
        }

        if (isContactGroupChecked) {
             const hasContactSelection = CONTACT_STD_OPTIONS.some(opt => selectedDiseases.has(opt));
             if (!hasContactSelection) {
                 alert('กรุณาเลือกประเภทของ Contact STD อย่างน้อย 1 รายการ');
                 return;
             }
        }

        // Add Other
        if (isOtherChecked && otherText.trim()) {
            finalDiseases.push(otherText.trim());
        }

        if (finalDiseases.length === 0) {
            alert('กรุณาเลือกโรคอย่างน้อย 1 รายการ');
            return;
        }

        onSave({ ...record, date, diseases: finalDiseases });
    };

    return (
        <div className="fixed inset-0 bg-black bg-opacity-50 z-[100] flex justify-center items-center p-4" onClick={onClose}>
            <div className="bg-white rounded-lg shadow-xl w-full max-w-2xl max-h-[90vh] overflow-y-auto" onClick={e => e.stopPropagation()}>
                <div className="p-6 border-b flex justify-between items-center sticky top-0 bg-white z-10">
                    <h3 className="text-xl font-semibold text-gray-800">แก้ไขข้อมูล STD</h3>
                    <button onClick={onClose} className="text-gray-400 hover:text-gray-600">&times;</button>
                </div>
                <form onSubmit={handleSubmit} className="p-6 space-y-6">
                     <div>
                        <label htmlFor="stdDateEdit" className={labelClass}>วันที่</label>
                        <DateInput id="stdDateEdit" value={date} onChange={(e) => setDate(e.target.value)} />
                    </div>

                    <StdSelectionForm 
                        selectedDiseases={selectedDiseases}
                        onToggleDisease={handleToggleDisease}
                        isSyphilisGroupChecked={isSyphilisGroupChecked}
                        onToggleSyphilisGroup={handleToggleSyphilisGroup}
                        isContactGroupChecked={isContactGroupChecked}
                        onToggleContactGroup={handleToggleContactGroup}
                        isOtherChecked={isOtherChecked}
                        otherText={otherText}
                        onToggleOther={setIsOtherChecked}
                        onOtherTextChange={setOtherText}
                    />

                    <div className="flex justify-end gap-x-3 pt-4 border-t">
                       <button onClick={onClose} type="button" className="px-6 py-2 text-sm font-medium text-gray-700 bg-white border border-gray-300 rounded-lg hover:bg-gray-50">
                           ยกเลิก
                       </button>
                       <button type="submit" className="px-6 py-2 text-sm font-medium text-white bg-emerald-600 rounded-lg hover:bg-emerald-700">
                           บันทึกการแก้ไข
                       </button>
                    </div>
                </form>
            </div>
        </div>
    );
};

export const StdTab: React.FC<StdTabProps> = ({ patient, onUpdatePatient }) => {
    const [date, setDate] = useState(toLocalISOString(new Date()));

    // Form States
    const [selectedDiseases, setSelectedDiseases] = useState<Set<string>>(new Set());

    const [isSyphilisGroupChecked, setIsSyphilisGroupChecked] = useState(false);
    const [isContactGroupChecked, setIsContactGroupChecked] = useState(false);

    const [isOtherChecked, setIsOtherChecked] = useState(false);
    const [otherText, setOtherText] = useState('');

    const [editingRecord, setEditingRecord] = useState<StdRecord | null>(null);

    const resetForm = () => {
        setDate(toLocalISOString(new Date()));
        setSelectedDiseases(new Set());
        setIsSyphilisGroupChecked(false);
        setIsContactGroupChecked(false);
        setIsOtherChecked(false);
        setOtherText('');
    };

    const handleDelete = (id: string) => {
        if (window.confirm('คุณแน่ใจหรือไม่ว่าต้องการลบข้อมูลนี้? การกระทำนี้ไม่สามารถย้อนกลับได้')) {
            const updatedRecords = (patient.stdInfo?.records || []).filter(rec => rec.id !== id);
            onUpdatePatient({ ...patient, stdInfo: { records: updatedRecords } });
        }
    };

    const handleAdd = (e: React.FormEvent) => {
        e.preventDefault();

        const finalDiseases = [...selectedDiseases];

         // Validation
        if (isSyphilisGroupChecked) {
             const hasSyphilisSelection = SYPHILIS_OPTIONS.some(opt => selectedDiseases.has(opt));
             if (!hasSyphilisSelection) {
                 alert('กรุณาเลือกประเภทของ Syphilis อย่างน้อย 1 รายการ');
                 return;
             }
        }

        if (isContactGroupChecked) {
             const hasContactSelection = CONTACT_STD_OPTIONS.some(opt => selectedDiseases.has(opt));
             if (!hasContactSelection) {
                 alert('กรุณาเลือกประเภทของ Contact STD อย่างน้อย 1 รายการ');
                 return;
             }
        }

        // Add Other
        if (isOtherChecked && otherText.trim()) {
            finalDiseases.push(otherText.trim());
        }

        if (finalDiseases.length === 0) {
            alert('กรุณาเลือกโรคอย่างน้อย 1 รายการ');
            return;
        }

        const currentRecords = patient.stdInfo?.records || [];
        const newRecord: StdRecord = {
            id: `std-${Date.now()}`,
            date,
            diseases: finalDiseases
        };
        const updatedRecords = [...currentRecords, newRecord];

        onUpdatePatient({ ...patient, stdInfo: { records: updatedRecords } });
        resetForm();
    };

    const handleUpdateRecord = (updatedRecord: StdRecord) => {
        const currentRecords = patient.stdInfo?.records || [];
        const updatedRecords = currentRecords.map(rec => rec.id === updatedRecord.id ? updatedRecord : rec);
        onUpdatePatient({ ...patient, stdInfo: { records: updatedRecords } });
        setEditingRecord(null);
    }

    const handleToggleDisease = (disease: string, checked: boolean) => {
        setSelectedDiseases(prev => {
            const next = new Set(prev);
            if (checked) next.add(disease);
            else next.delete(disease);
            return next;
        });
    };

    const handleToggleSyphilisGroup = (checked: boolean) => {
        setIsSyphilisGroupChecked(checked);
        if (!checked) {
            setSelectedDiseases(prev => {
                const next = new Set(prev);
                SYPHILIS_OPTIONS.forEach(opt => next.delete(opt));
                return next;
            });
        }
    };

    const handleToggleContactGroup = (checked: boolean) => {
        setIsContactGroupChecked(checked);
        if (!checked) {
            setSelectedDiseases(prev => {
                const next = new Set(prev);
                CONTACT_STD_OPTIONS.forEach(opt => next.delete(opt));
                return next;
            });
        }
    };

    const sortedRecords = [...(patient.stdInfo?.records || [])].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

    return (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            {/* Left Column: Form */}
            <form onSubmit={handleAdd} className="bg-white p-6 rounded-lg shadow-sm border">
                <h3 className="text-xl font-semibold text-gray-800 mb-6">เพิ่มข้อมูล STD</h3>
                <div className="space-y-6">
                    <div>
                        <label htmlFor="stdDate" className={labelClass}>วันที่</label>
                        <DateInput id="stdDate" value={date} onChange={(e) => setDate(e.target.value)} />
                    </div>

                    <div>
                        <label className={labelClass + " mb-2"}>เลือกโรคที่พบ</label>
                        <StdSelectionForm 
                            selectedDiseases={selectedDiseases}
                            onToggleDisease={handleToggleDisease}
                            isSyphilisGroupChecked={isSyphilisGroupChecked}
                            onToggleSyphilisGroup={handleToggleSyphilisGroup}
                            isContactGroupChecked={isContactGroupChecked}
                            onToggleContactGroup={handleToggleContactGroup}
                            isOtherChecked={isOtherChecked}
                            otherText={otherText}
                            onToggleOther={setIsOtherChecked}
                            onOtherTextChange={setOtherText}
                        />
                    </div>

                    <div className="flex justify-end gap-x-3 pt-4 border-t">
                       <button type="submit" className="w-full flex items-center justify-center px-6 py-2 text-sm font-medium text-white bg-emerald-600 rounded-lg hover:bg-emerald-700">
                           บันทึกข้อมูล
                       </button>
                    </div>
                </div>
            </form>

            {/* Right Column: History Timeline */}
             <div className="bg-white p-6 rounded-lg shadow-sm border">
                <h3 className="text-xl font-semibold text-gray-800 mb-6">ประวัติโรคติดต่อทางเพศสัมพันธ์</h3>
                {sortedRecords.length > 0 ? (
                    <div className="relative pl-5 max-h-[600px] overflow-y-auto pr-2">
                        <div className="absolute left-5 top-0 h-full w-0.5 bg-gray-200" aria-hidden="true"></div>
                        <div className="space-y-8">
                            {sortedRecords.map((record) => (
                                <div key={record.id} className="relative flex items-start group">
                                    <div className="absolute top-0 -left-5 z-10">
                                         <div className="flex items-center justify-center h-10 w-10 rounded-full bg-blue-100 text-blue-600">
                                            <StdIcon />
                                        </div>
                                    </div>
                                    <div className="ml-8 flex-grow bg-white p-4 rounded-lg border border-gray-200">
                                        <div className="flex justify-between items-center">
                                            <h3 className="font-semibold text-gray-900 text-md">วินิจฉัย STD</h3>
                                            <div className="flex items-center text-sm text-gray-500">
                                                <span>{formatThaiDateBE(record.date)}</span>
                                                <button 
                                                    type="button"
                                                    onClick={(e) => { e.preventDefault(); e.stopPropagation(); setEditingRecord(record); }} 
                                                    className="ml-3 p-1.5 text-gray-400 hover:text-emerald-600 hover:bg-emerald-50 rounded-full transition-colors" 
                                                    title="แก้ไข"
                                                >
                                                    <EditIcon className="h-4 w-4"/>
                                                </button>
                                                <button 
                                                    type="button"
                                                    onClick={(e) => { e.preventDefault(); e.stopPropagation(); handleDelete(record.id); }} 
                                                    className="ml-1 p-1.5 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-full transition-colors relative z-20" 
                                                    title="ลบข้อมูล"
                                                >
                                                    <TrashIcon className="h-4 w-4 pointer-events-none"/>
                                                </button>
                                            </div>
                                        </div>
                                        <div className="text-sm text-gray-600 mt-2 space-y-1">
                                            <ul className="list-disc list-inside">
                                                {record.diseases.map(d => <li key={d}>{d}</li>)}
                                            </ul>
                                        </div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                ) : (
                    <div className="text-center py-10">
                        <p className="text-gray-500">ยังไม่มีประวัติ</p>
                    </div>
                )}
            </div>

            <EditStdModal 
                isOpen={!!editingRecord}
                record={editingRecord}
                onClose={() => setEditingRecord(null)}
                onSave={handleUpdateRecord}
            />
        </div>
    );
};

import React, { useState, useMemo } from 'react';
import { Patient, PatientStatus, MedicalEventType } from '../types';
import { PlusIcon, SearchIcon, ChevronLeftIcon, ChevronRightIcon, TrashIcon } from './icons';
import { calculateAge, calculatePatientStatus, determineHbvStatus, determineHcvStatus, formatThaiDateShort } from './utils';
import { DateInput } from './DateInput';

interface PatientListProps {
  patients: Patient[];
  onSelectPatient: (id: number) => void;
  onAddNew: () => void;
  onDeletePatient: (id: number) => void;
}

const getStatusBadge = (status: PatientStatus | null) => {
  if (!status) {
      return <span className="text-slate-400">-</span>;
  }
  switch (status) {
    case PatientStatus.ACTIVE:
      return <span className="px-2.5 py-1 text-xs font-bold text-emerald-700 bg-emerald-100 border border-emerald-200 rounded-lg">Active</span>;
    case PatientStatus.LTFU:
      return <span className="px-2.5 py-1 text-xs font-bold text-red-700 bg-red-100 border border-red-200 rounded-lg">LTFU</span>;
    case PatientStatus.TRANSFERRED:
      return <span className="px-2.5 py-1 text-xs font-bold text-slate-700 bg-slate-100 border border-slate-200 rounded-lg">Transferred</span>;
    case PatientStatus.EXPIRED:
      return <span className="px-2.5 py-1 text-xs font-bold text-white bg-slate-700 border border-slate-600 rounded-lg">Expired</span>;
    case PatientStatus.RESTART:
        return <span className="px-2.5 py-1 text-xs font-bold text-orange-700 bg-orange-100 border border-orange-200 rounded-lg">Restart</span>;
    default:
      return <span>-</span>;
  }
};

// Common STDs for dropdown
const STD_DISEASE_OPTIONS = [
    'Syphilis', 'Gonorrhea', 'Chlamydia', 'Non-Gonorrhea', 
    'HSV', 'HPV', 'Trichomoniasis', 'PID', 'LGV', 'Chancroid', 'Monkey Pox'
];

const HBV_STATUS_OPTIONS = ['ไม่เป็น HBV', 'เป็น HBV', 'รอตรวจเพิ่มเติม', 'ไม่มีข้อมูล'];
const HCV_STATUS_OPTIONS = [
    'ไม่เป็น HCV', 'รอการตรวจเพิ่มเติม', 'เคยเป็น HCV หายเอง', 
    'เป็น HCV', 'กำลังรักษา HCV', 'เคยเป็น HCV รักษาหายแล้ว', 'เป็น HCV รักษาแล้วไม่หาย'
];

export const PatientList: React.FC<PatientListProps> = ({ patients, onSelectPatient, onAddNew, onDeletePatient }) => {
  // --- Filter States ---
  const [searchText, setSearchText] = useState('');

  // Appointment Date Range
  const [apptStartDate, setApptStartDate] = useState('');
  const [apptEndDate, setApptEndDate] = useState('');

  // Dropdown Filters
  const [statusFilter, setStatusFilter] = useState<string>('');
  const [hbvFilter, setHbvFilter] = useState<string>('');
  const [hcvFilter, setHcvFilter] = useState<string>('');
  const [stdFilter, setStdFilter] = useState<string>('');

  // Boolean Toggles
  const [tptFilter, setTptFilter] = useState(false);
  const [prepFilter, setPrepFilter] = useState(false);
  const [pepFilter, setPepFilter] = useState(false);

  // --- Pagination States ---
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 10;

  // --- Filtering Logic ---
  const filteredPatients = useMemo(() => {
    return patients.filter(p => {
        // Use strictly calculated status. If no date, this is null.
        const calculatedStatus = calculatePatientStatus(p);

        // 1. Text Search (HN, Name, Phone, CID)
        if (searchText) {
            const searchLower = searchText.toLowerCase();
            const fullName = `${p.firstName} ${p.lastName}`.toLowerCase();
            const matches = 
                p.hn.toLowerCase().includes(searchLower) ||
                (p.cid && p.cid.includes(searchLower)) ||
                fullName.includes(searchLower) ||
                (p.phone && p.phone.includes(searchLower));
            if (!matches) return false;
        }

        // 2. Status Filter
        if (statusFilter && calculatedStatus !== statusFilter) {
            return false;
        }

        // 3. Appointment Date Range
        if (apptStartDate || apptEndDate) {
            if (!p.nextAppointmentDate) return false;
            const apptDate = new Date(p.nextAppointmentDate);
            apptDate.setHours(0,0,0,0);

            if (apptStartDate) {
                const start = new Date(apptStartDate);
                start.setHours(0,0,0,0);
                if (apptDate < start) return false;
            }
            if (apptEndDate) {
                const end = new Date(apptEndDate);
                end.setHours(0,0,0,0);
                if (apptDate > end) return false;
            }
        }

        // 4. HBV Status
        if (hbvFilter) {
            const status = determineHbvStatus(p).text;
            if (status !== hbvFilter) return false;
        }

        // 5. HCV Status
        if (hcvFilter) {
            const status = determineHcvStatus(p).text;
            if (status !== hcvFilter) return false;
        }

        // 6. STD Filter (Specific Disease)
        if (stdFilter) {
            const hasStd = p.stdInfo?.records?.some(r => 
                r.diseases.some(d => d.toLowerCase().includes(stdFilter.toLowerCase()))
            );
            if (!hasStd) return false;
        }

        // 7. TPT Filter
        if (tptFilter) {
            const receivedTpt = p.medicalHistory.some(e => e.type === MedicalEventType.PROPHYLAXIS && e.details.TPT);
            if (!receivedTpt) return false;
        }

        // 8. PrEP Filter (Ever received)
        if (prepFilter) {
            const hasPrep = p.prepInfo?.records && p.prepInfo.records.length > 0;
            if (!hasPrep) return false;
        }

        // 9. PEP Filter (Ever received)
        if (pepFilter) {
            const hasPep = p.pepInfo?.records && p.pepInfo.records.length > 0;
            if (!hasPep) return false;
        }

        return true;
    }).sort((a, b) => {
        // Sort by updatedAt descending (newest first)
        const dateA = a.updatedAt ? new Date(a.updatedAt).getTime() : 0;
        const dateB = b.updatedAt ? new Date(b.updatedAt).getTime() : 0;
        return dateB - dateA;
    });
  }, [patients, searchText, statusFilter, apptStartDate, apptEndDate, hbvFilter, hcvFilter, stdFilter, tptFilter, prepFilter, pepFilter]);

  // --- Pagination Logic ---
  const totalPatients = filteredPatients.length;
  const totalPages = Math.ceil(totalPatients / itemsPerPage);
  const startIndex = (currentPage - 1) * itemsPerPage;
  const paginatedPatients = filteredPatients.slice(startIndex, startIndex + itemsPerPage);

  const handlePageChange = (newPage: number) => {
      if (newPage >= 1 && newPage <= totalPages) {
          setCurrentPage(newPage);
      }
  };

  const resetFilters = () => {
      setSearchText('');
      setApptStartDate('');
      setApptEndDate('');
      setStatusFilter('');
      setHbvFilter('');
      setHcvFilter('');
      setStdFilter('');
      setTptFilter(false);
      setPrepFilter(false);
      setPepFilter(false);
      setCurrentPage(1);
  };

  return (
    <div className="p-6 md:p-10 max-w-7xl mx-auto animate-fade-in-up">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
        <div>
            <h1 className="text-3xl font-bold text-slate-800 tracking-tight">รายชื่อผู้ป่วยทั้งหมด</h1>
            <p className="text-slate-500 mt-1">จัดการข้อมูลและสถานะผู้ป่วย</p>
        </div>
        <button 
            onClick={onAddNew} 
            className="flex items-center px-5 py-2.5 text-sm font-semibold text-white bg-emerald-600 rounded-xl hover:bg-emerald-700 shadow-md shadow-emerald-500/20 transition-all hover:-translate-y-0.5 hover:shadow-lg active:scale-95"
        >
          <PlusIcon className="mr-2 h-5 w-5" />
          เพิ่มผู้ป่วยใหม่
        </button>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden transition-all duration-300 hover:shadow-md">

        {/* --- Advanced Filters Section --- */}
        <div className="p-6 bg-slate-50/50 border-b border-slate-200 space-y-5">

            {/* Row 1: Search & Date Range */}
            <div className="grid grid-cols-1 md:grid-cols-12 gap-4">
                <div className="md:col-span-4 relative group">
                    <div className="absolute inset-y-0 left-0 flex items-center pl-3 pointer-events-none transition-transform duration-300 group-focus-within:scale-110">
                        <SearchIcon className="text-slate-400 group-focus-within:text-emerald-500 transition-colors" />
                    </div>
                    <input
                        type="text"
                        placeholder="ค้นหา HN, เลขบัตรปชช, ชื่อ, เบอร์โทร..."
                        value={searchText}
                        onChange={(e) => setSearchText(e.target.value)}
                        className="w-full pl-10 pr-4 py-2.5 bg-white border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-emerald-500/20 focus:border-emerald-500 outline-none transition-all shadow-sm focus:shadow-md"
                    />
                </div>
                <div className="md:col-span-8 flex flex-col md:flex-row items-start md:items-center gap-2">
                    <div className="flex flex-col sm:flex-row items-start sm:items-center gap-3 w-full p-2 bg-white rounded-xl border border-slate-200 shadow-sm transition-shadow hover:shadow-md">
                         <span className="text-sm font-medium text-slate-500 whitespace-nowrap pl-2">วันนัด:</span>
                         <div className="flex flex-col sm:flex-row gap-2 w-full items-center">
                             <div className="w-full"><DateInput value={apptStartDate} onChange={(e) => setApptStartDate(e.target.value)} className="w-full" /></div>
                            <span className="text-slate-400 hidden sm:block">→</span>
                            <div className="w-full"><DateInput value={apptEndDate} onChange={(e) => setApptEndDate(e.target.value)} className="w-full" /></div>
                         </div>
                    </div>
                </div>
            </div>

            {/* Row 2: Categorical Filters */}
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                 <select 
                    value={statusFilter} 
                    onChange={(e) => setStatusFilter(e.target.value)} 
                    className="w-full px-3 py-2.5 bg-white border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-emerald-500/20 focus:border-emerald-500 outline-none shadow-sm cursor-pointer hover:border-emerald-300 transition-all hover:-translate-y-0.5"
                 >
                     <option value="">สถานะการรักษา (ทั้งหมด)</option>
                     {Object.values(PatientStatus).map(s => <option key={s} value={s}>{s}</option>)}
                 </select>

                 <select 
                    value={hbvFilter} 
                    onChange={(e) => setHbvFilter(e.target.value)} 
                    className="w-full px-3 py-2.5 bg-white border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-emerald-500/20 focus:border-emerald-500 outline-none shadow-sm cursor-pointer hover:border-emerald-300 transition-all hover:-translate-y-0.5"
                 >
                     <option value="">สรุปผล HBV (ทั้งหมด)</option>
                     {HBV_STATUS_OPTIONS.map(s => <option key={s} value={s}>{s}</option>)}
                 </select>

                 <select 
                    value={hcvFilter} 
                    onChange={(e) => setHcvFilter(e.target.value)} 
                    className="w-full px-3 py-2.5 bg-white border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-emerald-500/20 focus:border-emerald-500 outline-none shadow-sm cursor-pointer hover:border-emerald-300 transition-all hover:-translate-y-0.5"
                 >
                     <option value="">สรุปผล HCV (ทั้งหมด)</option>
                     {HCV_STATUS_OPTIONS.map(s => <option key={s} value={s}>{s}</option>)}
                 </select>

                 <select 
                    value={stdFilter} 
                    onChange={(e) => setStdFilter(e.target.value)} 
                    className="w-full px-3 py-2.5 bg-white border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-emerald-500/20 focus:border-emerald-500 outline-none shadow-sm cursor-pointer hover:border-emerald-300 transition-all hover:-translate-y-0.5"
                 >
                     <option value="">ประวัติ STD (โรค)</option>
                     {STD_DISEASE_OPTIONS.map(s => <option key={s} value={s}>{s}</option>)}
                 </select>
            </div>

            {/* Row 3: Toggles & Reset */}
            <div className="flex flex-wrap items-center justify-between gap-4 pt-2">
                <div className="flex gap-2 flex-wrap">
                    <button 
                        onClick={() => setTptFilter(!tptFilter)}
                        className={`px-4 py-1.5 text-xs font-bold rounded-full border transition-all duration-300 ${tptFilter ? 'bg-emerald-100 text-emerald-700 border-emerald-200 shadow-sm scale-105' : 'bg-white text-slate-500 border-slate-200 hover:bg-slate-50 hover:border-slate-300 hover:scale-105'}`}
                    >
                        {tptFilter ? '✓ TPT' : 'TPT'}
                    </button>
                    <button 
                        onClick={() => setPrepFilter(!prepFilter)}
                        className={`px-4 py-1.5 text-xs font-bold rounded-full border transition-all duration-300 ${prepFilter ? 'bg-indigo-100 text-indigo-700 border-indigo-200 shadow-sm scale-105' : 'bg-white text-slate-500 border-slate-200 hover:bg-slate-50 hover:border-slate-300 hover:scale-105'}`}
                    >
                        {prepFilter ? '✓ PrEP' : 'PrEP'}
                    </button>
                    <button 
                        onClick={() => setPepFilter(!pepFilter)}
                        className={`px-4 py-1.5 text-xs font-bold rounded-full border transition-all duration-300 ${pepFilter ? 'bg-purple-100 text-purple-700 border-purple-200 shadow-sm scale-105' : 'bg-white text-slate-500 border-slate-200 hover:bg-slate-50 hover:border-slate-300 hover:scale-105'}`}
                    >
                        {pepFilter ? '✓ PEP' : 'PEP'}
                    </button>
                </div>

                <button onClick={resetFilters} className="text-sm font-medium text-red-600 hover:text-red-700 hover:underline px-2 transition-colors flex items-center group">
                    <span className="group-hover:rotate-180 transition-transform duration-500 mr-1">↺</span> ล้างตัวกรอง (Reset)
                </button>
            </div>
        </div>

        {/* --- Table --- */}
        <div className="overflow-x-auto">
          <table className="w-full text-sm text-left text-slate-600">
            <thead className="text-xs text-slate-500 uppercase bg-slate-50 border-b border-slate-200 font-semibold tracking-wider">
              <tr>
                <th scope="col" className="px-6 py-4">HN</th>
                <th scope="col" className="px-6 py-4">ชื่อ-สกุล</th>
                <th scope="col" className="px-6 py-4">อายุ</th>
                <th scope="col" className="px-6 py-4">เบอร์โทร</th>
                <th scope="col" className="px-6 py-4">สิทธิ์การรักษา</th>
                <th scope="col" className="px-6 py-4">วันนัดหมาย</th>
                <th scope="col" className="px-6 py-4">สถานะ</th>
                <th scope="col" className="px-6 py-4 text-center">Action</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {paginatedPatients.length > 0 ? paginatedPatients.map((patient, index) => {
                // Use strictly calculated status
                const calculatedStatus = calculatePatientStatus(patient);
                return (
                    <tr 
                        key={patient.id} 
                        className="bg-white hover:bg-slate-50 transition-colors opacity-0 animate-fade-in-up"
                        style={{ animationDelay: `${index * 50}ms` }}
                    >
                        <td className="px-6 py-4 font-semibold text-emerald-700">{patient.hn}</td>
                        <td className="px-6 py-4 font-medium text-slate-900">{`${patient.firstName || '-'} ${patient.lastName || ''}`}</td>
                        <td className="px-6 py-4">{calculateAge(patient.dob)}</td>
                        <td className="px-6 py-4 font-mono text-slate-500">{patient.phone || '-'}</td>
                        <td className="px-6 py-4 truncate max-w-[150px]" title={patient.healthcareScheme}>{patient.healthcareScheme || '-'}</td>
                        <td className="px-6 py-4">
                            {patient.nextAppointmentDate ? (
                                <span className="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-blue-50 text-blue-700">
                                    {formatThaiDateShort(patient.nextAppointmentDate)}
                                </span>
                            ) : '-'}
                        </td>
                        <td className="px-6 py-4">{getStatusBadge(calculatedStatus)}</td>
                        <td className="px-6 py-4 text-center">
                            <div className="flex items-center justify-center space-x-3">
                                <button onClick={() => onSelectPatient(patient.id)} className="font-semibold text-emerald-600 hover:text-emerald-800 transition-all hover:scale-105 active:scale-95">
                                    ดูข้อมูล
                                </button>
                                <button 
                                    type="button"
                                    onClick={(e) => { 
                                        e.preventDefault();
                                        e.stopPropagation(); 
                                        onDeletePatient(patient.id); 
                                    }} 
                                    className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-full transition-all hover:rotate-12 active:scale-95"
                                    title="ลบผู้ป่วย"
                                >
                                    <TrashIcon className="h-4 w-4 pointer-events-none" />
                                </button>
                            </div>
                        </td>
                    </tr>
                );
              }) : (
                  <tr>
                      <td colSpan={8} className="px-6 py-16 text-center text-slate-400 bg-slate-50/30">
                          <div className="flex flex-col items-center justify-center animate-pulse">
                              <SearchIcon className="h-10 w-10 text-slate-300 mb-2" />
                              <p>ไม่พบข้อมูลผู้ป่วยที่ตรงกับเงื่อนไข</p>
                          </div>
                      </td>
                  </tr>
              )}
            </tbody>
          </table>
        </div>

        {/* --- Pagination Controls --- */}
        <div className="flex flex-col md:flex-row justify-between items-center px-6 py-4 bg-white border-t border-slate-200">
            <p className="text-sm text-slate-500 mb-4 md:mb-0">
                แสดง <span className="font-semibold text-slate-800">{filteredPatients.length > 0 ? startIndex + 1 : 0}</span> ถึง <span className="font-semibold text-slate-800">{Math.min(startIndex + itemsPerPage, totalPatients)}</span> จาก <span className="font-semibold text-slate-800">{totalPatients}</span> รายการ
            </p>
            <div className="flex items-center space-x-2">
                <button 
                    onClick={() => handlePageChange(currentPage - 1)}
                    disabled={currentPage === 1}
                    className="p-2 rounded-lg hover:bg-slate-100 disabled:opacity-30 disabled:cursor-not-allowed transition-colors text-slate-600 hover:-translate-x-1"
                >
                    <ChevronLeftIcon />
                </button>

                {Array.from({ length: Math.min(5, totalPages) }, (_, i) => {
                    let pNum = i + 1;
                    if (totalPages > 5 && currentPage > 3) {
                        pNum = currentPage - 2 + i;
                    }
                    if (pNum > totalPages) return null;

                    return (
                         <button 
                            key={pNum}
                            onClick={() => handlePageChange(pNum)}
                            className={`w-8 h-8 rounded-lg text-sm font-medium transition-all duration-200 ${currentPage === pNum ? 'bg-emerald-600 text-white shadow-md shadow-emerald-500/30 scale-110' : 'text-slate-600 hover:bg-slate-100 hover:scale-105'}`}
                        >
                            {pNum}
                        </button>
                    );
                })}

                <button 
                    onClick={() => handlePageChange(currentPage + 1)}
                    disabled={currentPage === totalPages || totalPages === 0}
                    className="p-2 rounded-lg hover:bg-slate-100 disabled:opacity-30 disabled:cursor-not-allowed transition-colors text-slate-600 hover:translate-x-1"
                >
                    <ChevronRightIcon />
                </button>
            </div>
        </div>

      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Patient, PatientStatus } from '../types';
import { calculateAgeBreakdown, calculateDobFromAge, calculatePatientStatus, inputClass, labelClass } from './utils';
import { ThaiAddressSelector } from './ThaiAddressSelector';
import { DateInput } from './DateInput';

export type NewPatientData = Omit<Patient, 'id' | 'medicalHistory' | 'registrationDate'>;

interface PatientFormProps {
    onSave: (patient: NewPatientData) => void;
    onCancel: () => void;
}

const HOSPITALS = [
    'โรงพยาบาลกันทรวิชัย',
    'โรงพยาบาลกุดรัง',
    'โรงพยาบาลแกดำ',
    'โรงพยาบาลโกสุมพิสัย',
    'โรงพยาบาลชื่นชม',
    'โรงพยาบาลเชียงยืน',
    'โรงพยาบาลนาเชือก',
    'โรงพยาบาลนาดูน',
    'โรงพยาบาลบรบือ',
    'โรงพยาบาลพยัคฆภูมิพิสัย',
    'โรงพยาบาลยางสีสุราช',
    'โรงพยาบาลวาปีปทุม',
    'โรงพยาบาลสุทธาเวช',
    'โรงพยาบาลร้อยเอ็ด',
    'โรงพยาบาลขอนแก่น',
    'โรงพยาบาลศรีนครินทร์'
];

export const PatientForm: React.FC<PatientFormProps> = ({ onSave, onCancel }) => {
    const [formData, setFormData] = useState<NewPatientData>({
        hn: '',
        cid: '', 
        napId: '',
        title: '',
        firstName: '',
        lastName: '',
        dob: '',
        sex: '',
        riskBehavior: '', 
        status: PatientStatus.ACTIVE, 
        occupation: '',
        partnerStatus: '', 
        partnerHivStatus: '', 
        address: '',
        subdistrict: '',
        district: '',
        province: '',
        phone: '',
        healthcareScheme: '',
        referralType: 'มหาสารคาม',
        referredFrom: '',
        referralDate: '',
        nextAppointmentDate: '',
        referOutDate: '',
        referOutLocation: '',
        deathDate: '',
        causeOfDeath: undefined,
    });

    const [age, setAge] = useState({ years: '', months: '', days: '' });
    const [isDeceased, setIsDeceased] = useState(false);

    // Track "Other" visibility for both fields
    const isReferredFromOther = formData.referredFrom !== '' && !HOSPITALS.includes(formData.referredFrom);
    const isReferOutOther = formData.referOutLocation !== '' && !HOSPITALS.includes(formData.referOutLocation);

    // Internal UI states for the selects
    const [selectedReferIn, setSelectedReferIn] = useState(formData.referredFrom === '' ? '' : (HOSPITALS.includes(formData.referredFrom) ? formData.referredFrom : 'อื่นๆ ระบุ'));
    const [selectedReferOut, setSelectedReferOut] = useState(formData.referOutLocation === '' ? '' : (HOSPITALS.includes(formData.referOutLocation) ? formData.referOutLocation : 'อื่นๆ ระบุ'));

    // Auto-calculate status when relevant dates change
    useEffect(() => {
        const computedStatus = calculatePatientStatus(formData);
        const newStatus = computedStatus || PatientStatus.ACTIVE;
        if (formData.status !== newStatus) {
            setFormData(prev => ({ ...prev, status: newStatus }));
        }
    }, [formData.deathDate, formData.referOutDate, formData.nextAppointmentDate]);


    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement> | { target: { name: string; value: string } }) => {
        const { name, value } = e.target;

        let updates: Partial<NewPatientData> = { [name]: value };

        if (name === 'cid') {
            const numericValue = value.replace(/\D/g, '').slice(0, 13);
            updates.cid = numericValue;
        }

        if (name === 'title') {
            if (value === 'นาย') {
                updates.sex = 'ชาย';
            } else if (value === 'นาง' || value === 'นางสาว') {
                updates.sex = 'หญิง';
            }
        } else if (name === 'sex') {
            if (value === 'ชาย') {
                updates.title = 'นาย';
            } else if (value === 'หญิง') {
                if (formData.title === 'นาย') {
                    updates.title = 'นางสาว';
                }
            }
        } else if (name === 'referralType' && value === 'มหาสารคาม') {
            updates.referredFrom = '';
            updates.referralDate = '';
            setSelectedReferIn('');
        }

        setFormData(prev => ({ ...prev, ...updates }));
    };

    const handleHospitalSelectChange = (field: 'referredFrom' | 'referOutLocation', value: string) => {
        if (field === 'referredFrom') {
            setSelectedReferIn(value);
            if (value === 'อื่นๆ ระบุ') {
                setFormData(prev => ({ ...prev, referredFrom: '' }));
            } else {
                setFormData(prev => ({ ...prev, referredFrom: value }));
            }
        } else {
            setSelectedReferOut(value);
            if (value === 'อื่นๆ ระบุ') {
                setFormData(prev => ({ ...prev, referOutLocation: '' }));
            } else {
                setFormData(prev => ({ ...prev, referOutLocation: value }));
            }
        }
    };

    const handleAddressSelectorChange = (key: 'subdistrict' | 'district' | 'province', value: string) => {
        setFormData(prev => ({ ...prev, [key]: value }));
    };

    const handleDeceasedChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const checked = e.target.checked;
        setIsDeceased(checked);
        if (!checked) {
            setFormData(prev => ({ ...prev, deathDate: '', causeOfDeath: undefined }));
        }
    };

    const handleDobChange = (e: { target: { value: string } }) => {
        const val = e.target.value;
        setFormData(prev => ({ ...prev, dob: val }));
        const breakdown = calculateAgeBreakdown(val);
        setAge(breakdown);
    };

    const handleAgeChange = (field: 'years' | 'months' | 'days', val: string) => {
        const newAge = { ...age, [field]: val };
        setAge(newAge);
        const dob = calculateDobFromAge(newAge.years, newAge.months, newAge.days);
        setFormData(prev => ({ ...prev, dob }));
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (formData.cid && formData.cid.length !== 13) {
            alert("เลขบัตรประชาชนต้องมี 13 หลัก");
            return;
        }
        onSave(formData);
    };

    return (
        <div className="p-6 md:p-8">
            <div className="mb-6">
                <div className="text-sm text-gray-500 mb-2">
                    <a href="#" onClick={(e) => { e.preventDefault(); onCancel(); }} className="hover:underline">รายชื่อผู้ป่วย</a> /
                    <span className="text-gray-700 font-medium"> เพิ่มผู้ป่วยใหม่</span>
                </div>
                <h1 className="text-2xl font-bold text-gray-800">เพิ่มผู้ป่วยใหม่</h1>
            </div>

            <form onSubmit={handleSubmit}>
                <div className="bg-white p-6 rounded-lg shadow-sm mb-6">
                    <h3 className="text-lg font-semibold text-gray-800 mb-6">ข้อมูลระบุตัวตนผู้ป่วย (Patient Identification)</h3>
                    <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
                        <div>
                            <label htmlFor="hn" className={labelClass}>HN (Hospital Number)</label>
                            <input type="text" name="hn" id="hn" value={formData.hn} onChange={handleChange} className={inputClass} required />
                        </div>
                        <div>
                             <label htmlFor="cid" className={labelClass}>เลขบัตรประชาชน (National ID)</label>
                             <input 
                                type="text" 
                                name="cid" 
                                id="cid" 
                                value={formData.cid} 
                                onChange={handleChange} 
                                className={inputClass} 
                                placeholder="13 หลัก"
                                maxLength={13}
                            />
                        </div>
                        <div>
                            <label htmlFor="napId" className={labelClass}>NAP ID</label>
                            <input type="text" name="napId" id="napId" value={formData.napId} onChange={handleChange} className={inputClass} />
                        </div>
                         <div>
                             <label className={labelClass}>สถานะ (คำนวณอัตโนมัติ)</label>
                             <input 
                                type="text" 
                                disabled 
                                value={calculatePatientStatus(formData) || '-'} 
                                className={`${inputClass} bg-gray-100 text-gray-500 cursor-not-allowed`} 
                            />
                        </div>
                    </div>
                </div>

                <div className="bg-white p-6 rounded-lg shadow-sm mb-6">
                    <h3 className="text-lg font-semibold text-gray-800 mb-6">ข้อมูลประชากร (Demographic Information)</h3>
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                         <div>
                            <label htmlFor="title" className={labelClass}>คำนำหน้า</label>
                            <select name="title" id="title" value={formData.title} onChange={handleChange} className={inputClass}>
                                <option value="">-- เลือก --</option>
                                <option>นาย</option>
                                <option>นาง</option>
                                <option>นางสาว</option>
                                <option>อื่นๆ</option>
                            </select>
                        </div>
                        <div>
                            <label htmlFor="firstName" className={labelClass}>ชื่อ</label>
                            <input type="text" name="firstName" id="firstName" value={formData.firstName} onChange={handleChange} className={inputClass} />
                        </div>
                        <div>
                            <label htmlFor="lastName" className={labelClass}>นามสกุล</label>
                            <input type="text" name="lastName" id="lastName" value={formData.lastName} onChange={handleChange} className={inputClass} />
                        </div>
                         <div>
                            <label htmlFor="dob" className={labelClass}>วันเกิด</label>
                            <DateInput name="dob" id="dob" value={formData.dob} onChange={handleDobChange} />
                        </div>
                        <div>
                            <label className={labelClass}>อายุ (คำนวณอัตโนมัติ)</label>
                            <div className="flex space-x-2 mt-1">
                                <div className="flex-1 relative">
                                    <input 
                                        type="number" 
                                        min="0"
                                        placeholder="ปี" 
                                        value={age.years} 
                                        onChange={(e) => handleAgeChange('years', e.target.value)} 
                                        className="block w-full px-2 py-2 bg-white border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-emerald-500 focus:border-emerald-500 sm:text-sm" 
                                    />
                                    <span className="absolute right-2 top-2 text-xs text-gray-400">ปี</span>
                                </div>
                                <div className="flex-1 relative">
                                    <input 
                                        type="number" 
                                        min="0"
                                        max="11"
                                        placeholder="เดือน" 
                                        value={age.months} 
                                        onChange={(e) => handleAgeChange('months', e.target.value)} 
                                        className="block w-full px-2 py-2 bg-white border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-emerald-500 focus:border-emerald-500 sm:text-sm" 
                                    />
                                    <span className="absolute right-2 top-2 text-xs text-gray-400">ด</span>
                                </div>
                                <div className="flex-1 relative">
                                    <input 
                                        type="number" 
                                        min="0"
                                        max="31"
                                        placeholder="วัน" 
                                        value={age.days} 
                                        onChange={(e) => handleAgeChange('days', e.target.value)} 
                                        className="block w-full px-2 py-2 bg-white border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-emerald-500 focus:border-emerald-500 sm:text-sm" 
                                    />
                                    <span className="absolute right-2 top-2 text-xs text-gray-400">ว</span>
                                </div>
                            </div>
                        </div>
                        <div>
                            <label htmlFor="sex" className={labelClass}>เพศ</label>
                            <select name="sex" id="sex" value={formData.sex} onChange={handleChange} className={inputClass}>
                                <option value="">-- เลือก --</option>
                                <option>ชาย</option>
                                <option>หญิง</option>
                            </select>
                        </div>
                        <div>
                            <label htmlFor="occupation" className={labelClass}>อาชีพ/สถานศึกษา</label>
                            <input type="text" name="occupation" id="occupation" value={formData.occupation} onChange={handleChange} className={inputClass} />
                        </div>
                    </div>
                </div>

                <div className="bg-white p-6 rounded-lg shadow-sm mb-6">
                    <h3 className="text-lg font-semibold text-gray-800 mb-6">ข้อมูลทางการแพทย์และพฤติกรรม (Medical & Behavioral Information)</h3>
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                        <div>
                            <label htmlFor="partnerStatus" className={labelClass}>สถานะคู่นอน</label>
                            <select name="partnerStatus" id="partnerStatus" value={formData.partnerStatus} onChange={handleChange} className={inputClass}>
                                <option value="">-- เลือก --</option>
                                <option>ไม่มี</option>
                                <option>มีคู่นอน</option>
                            </select>
                        </div>
                        <div>
                            <label htmlFor="partnerHivStatus" className={labelClass}>ผลเลือดของคู่นอน</label>
                            <select name="partnerHivStatus" id="partnerHivStatus" value={formData.partnerHivStatus} onChange={handleChange} className={inputClass}>
                                <option value="">-- เลือก --</option>
                                <option>ไม่ทราบ</option>
                                <option>บวก (Positive)</option>
                                <option>ลบ (Negative)</option>
                            </select>
                        </div>
                        <div>
                            <label htmlFor="riskBehavior" className={labelClass}>พฤติกรรมเสี่ยง</label>
                            <select name="riskBehavior" id="riskBehavior" value={formData.riskBehavior} onChange={handleChange} className={inputClass}>
                                <option value="">-- เลือก --</option>
                                <option value="MSM insertive">MSM insertive</option>
                                <option value="MSM receptive">MSM receptive</option>
                                <option value="MSM both">MSM both</option>
                                <option value="Bisexual">Bisexual</option>
                                <option value="Transgender">Transgender</option>
                                <option value="Sex worker">Sex worker</option>
                                <option value="IDU">IDU</option>
                                <option value="Heterosexual">Heterosexual</option>
                                <option value="Other">Other</option>
                            </select>
                        </div>
                    </div>
                </div>

                <div className="bg-white p-6 rounded-lg shadow-sm mb-6">
                    <h3 className="text-lg font-semibold text-gray-800 mb-6">ข้อมูลการติดต่อและสิทธิ์ (Contact & Eligibility)</h3>
                    <div className="grid grid-cols-1 gap-6">
                        <ThaiAddressSelector 
                            province={formData.province || ''}
                            district={formData.district || ''}
                            subdistrict={formData.subdistrict || ''}
                            onChange={handleAddressSelectorChange}
                        />

                        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                             <div className="md:col-span-3">
                                <label htmlFor="address" className={labelClass}>ที่อยู่ (รายละเอียด)</label>
                                <input type="text" name="address" id="address" value={formData.address} onChange={handleChange} className={inputClass} placeholder="บ้านเลขที่ หมู่ ถนน ซอย..." />
                            </div>
                            <div>
                                <label htmlFor="phone" className={labelClass}>เบอร์โทรศัพท์</label>
                                <input type="tel" name="phone" id="phone" value={formData.phone} onChange={handleChange} className={inputClass} />
                            </div>
                            <div>
                                <label htmlFor="healthcareScheme" className={labelClass}>สิทธิการรักษา</label>
                                 <select name="healthcareScheme" id="healthcareScheme" value={formData.healthcareScheme} onChange={handleChange} className={inputClass}>
                                    <option value="">-- เลือก --</option>
                                    <option>บัตรทอง นอกเขต</option>
                                    <option>บัตรทอง ในเขต</option>
                                    <option>ประกันสังคม นอกเขต</option>
                                    <option>ประกันสังคม ในเขต</option>
                                    <option>จ่ายตรง กรมบัญชีกลาง</option>
                                    <option>จ่ายตรง ท้องถิ่น</option>
                                    <option>ชำระเงินเอง</option>
                                </select>
                            </div>
                             <div>
                                <label htmlFor="nextAppointmentDate" className={labelClass}>วันนัดหมายครั้งถัดไป</label>
                                <DateInput name="nextAppointmentDate" id="nextAppointmentDate" value={formData.nextAppointmentDate} onChange={handleChange} />
                            </div>
                        </div>
                    </div>
                </div>

                <div className="bg-white p-6 rounded-lg shadow-sm mb-6">
                     <h3 className="text-lg font-semibold text-gray-800 mb-6">ข้อมูลการส่งตัว (Referral Information)</h3>

                     {/* Refer In Section */}
                     <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6 pb-6 border-b">
                        <div className="md:col-span-2">
                            <label className={labelClass}>การส่งตัวเข้า (Refer In)</label>
                            <div className="mt-2 flex gap-x-6">
                                <div className="flex items-center">
                                    <input
                                        id="referralTypeMahasarakhamForm"
                                        name="referralType"
                                        type="radio"
                                        value="มหาสารคาม"
                                        checked={formData.referralType === 'มหาสารคาม'}
                                        onChange={handleChange}
                                        className="h-4 w-4 border-gray-300 text-emerald-600 focus:ring-emerald-500"
                                    />
                                    <label htmlFor="referralTypeMahasarakhamForm" className="ml-2 block text-sm font-medium text-gray-700">
                                        ผู้ป่วยมหาสารคาม
                                    </label>
                                </div>
                                <div className="flex items-center">
                                    <input
                                        id="referralTypeOtherForm"
                                        name="referralType"
                                        type="radio"
                                        value="ที่อื่น"
                                        checked={formData.referralType === 'ที่อื่น'}
                                        onChange={handleChange}
                                        className="h-4 w-4 border-gray-300 text-emerald-600 focus:ring-emerald-500"
                                    />
                                    <label htmlFor="referralTypeOtherForm" className="ml-2 block text-sm font-medium text-gray-700">
                                        ผู้ป่วยที่อื่น
                                    </label>
                                </div>
                            </div>
                        </div>
                        {formData.referralType === 'ที่อื่น' && (
                            <>
                                <div>
                                    <label htmlFor="referralDate" className={labelClass}>วันที่ส่งตัว</label>
                                    <DateInput name="referralDate" id="referralDate" value={formData.referralDate} onChange={handleChange} />
                                </div>
                                <div>
                                    <label htmlFor="referredFromSelect" className={labelClass}>ส่งตัวมาจาก</label>
                                    <select 
                                        id="referredFromSelect" 
                                        value={selectedReferIn} 
                                        onChange={(e) => handleHospitalSelectChange('referredFrom', e.target.value)} 
                                        className={inputClass}
                                    >
                                        <option value="">-- เลือกโรงพยาบาล --</option>
                                        {HOSPITALS.map(h => <option key={h} value={h}>{h}</option>)}
                                        <option value="อื่นๆ ระบุ">อื่นๆ ระบุ</option>
                                    </select>
                                    {selectedReferIn === 'อื่นๆ ระบุ' && (
                                        <div className="mt-2 animate-in fade-in slide-in-from-top-1 duration-200">
                                            <input 
                                                type="text" 
                                                name="referredFrom" 
                                                placeholder="ระบุชื่อโรงพยาบาล..." 
                                                value={formData.referredFrom} 
                                                onChange={handleChange} 
                                                className={inputClass} 
                                            />
                                        </div>
                                    )}
                                </div>
                            </>
                        )}
                     </div>

                     {/* Refer Out Section */}
                     <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6 pb-6 border-b">
                        <div className="md:col-span-2">
                            <label className="block text-sm font-semibold text-gray-800">การส่งตัวออก (Refer Out)</label>
                        </div>
                        <div>
                            <label htmlFor="referOutDate" className={labelClass}>วันที่ส่งตัวออก</label>
                            <DateInput name="referOutDate" id="referOutDate" value={formData.referOutDate} onChange={handleChange} />
                        </div>
                         <div>
                            <label htmlFor="referOutLocationSelect" className={labelClass}>ส่งตัวไปที่</label>
                            <select 
                                id="referOutLocationSelect" 
                                value={selectedReferOut} 
                                onChange={(e) => handleHospitalSelectChange('referOutLocation', e.target.value)} 
                                className={inputClass}
                            >
                                <option value="">-- เลือกโรงพยาบาล --</option>
                                {HOSPITALS.map(h => <option key={h} value={h}>{h}</option>)}
                                <option value="อื่นๆ ระบุ">อื่นๆ ระบุ</option>
                            </select>
                            {selectedReferOut === 'อื่นๆ ระบุ' && (
                                <div className="mt-2 animate-in fade-in slide-in-from-top-1 duration-200">
                                    <input 
                                        type="text" 
                                        name="referOutLocation" 
                                        placeholder="ระบุชื่อโรงพยาบาล..." 
                                        value={formData.referOutLocation} 
                                        onChange={handleChange} 
                                        className={inputClass} 
                                    />
                                </div>
                            )}
                        </div>
                     </div>

                     {/* Death Section */}
                     <div>
                        <div className="flex items-center">
                             <input 
                                type="checkbox" 
                                id="isDeceasedCheck" 
                                checked={isDeceased} 
                                onChange={handleDeceasedChange} 
                                className="h-4 w-4 rounded border-gray-300 text-emerald-600 focus:ring-emerald-500" 
                            />
                             <label htmlFor="isDeceasedCheck" className="ml-2 text-sm font-semibold text-gray-800">เสียชีวิต (Deceased)</label>
                        </div>
                        {isDeceased && (
                           <div className="mt-4 pl-6 space-y-4">
                               <div>
                                   <label htmlFor="deathDate" className={labelClass}>วันที่เสียชีวิต</label>
                                   <DateInput name="deathDate" id="deathDate" value={formData.deathDate} onChange={handleChange} />
                               </div>
                               <div>
                                   <label className={labelClass}>สาเหตุการเสียชีวิต</label>
                                   <div className="flex items-center space-x-4 mt-2">
                                        <label className="inline-flex items-center">
                                            <input 
                                                type="radio" 
                                                name="causeOfDeath" 
                                                value="HIV-related" 
                                                checked={formData.causeOfDeath === 'HIV-related'} 
                                                onChange={handleChange} 
                                                className="h-4 w-4 border-gray-300 text-emerald-600 focus:ring-emerald-500" 
                                            />
                                            <span className="ml-2 text-sm text-gray-700">HIV related death</span>
                                        </label>
                                        <label className="inline-flex items-center">
                                            <input 
                                                type="radio" 
                                                name="causeOfDeath" 
                                                value="Non-HIV-related" 
                                                checked={formData.causeOfDeath === 'Non-HIV-related'} 
                                                onChange={handleChange} 
                                                className="h-4 w-4 border-gray-300 text-emerald-600 focus:ring-emerald-500" 
                                            />
                                            <span className="ml-2 text-sm text-gray-700">Non-HIV related death</span>
                                        </label>
                                   </div>
                               </div>
                           </div>
                        )}
                     </div>
                </div>


                <div className="flex justify-end gap-4 mt-8 pt-6 border-t">
                    <button type="button" onClick={onCancel} className="px-6 py-2 text-sm font-medium text-gray-700 bg-white border border-gray-300 rounded-lg hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-gray-500">
                        ยกเลิก
                    </button>
                    <button type="submit" className="px-6 py-2 text-sm font-medium text-white bg-emerald-600 rounded-lg hover:bg-emerald-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-emerald-500">
                        บันทึกข้อมูล
                    </button>
                </div>
            </form>
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { Patient, PatientStatus } from '../../types';
import { DisplayField, calculateAgeBreakdown, calculateDobFromAge, calculatePatientStatus, formatThaiDateBE, inputClass, labelClass } from '../utils';
import { EditIcon } from '../icons';
import { ThaiAddressSelector } from '../ThaiAddressSelector';
import { DateInput } from '../DateInput';

interface GeneralInfoTabProps {
  patient: Patient;
  onUpdate: (patient: Patient) => void;
}

type EditSection = 'ID' | 'DEMO' | 'MED' | 'CONTACT' | 'REFER' | null;

const HOSPITALS = [
    'โรงพยาบาลกันทรวิชัย',
    'โรงพยาบาลกุดรัง',
    'โรงพยาบาลแกดำ',
    'โรงพยาบาลโกสุมพิสัย',
    'โรงพยาบาลชื่นชม',
    'โรงพยาบาลเชียงยืน',
    'โรงพยาบาลนาเชือก',
    'โรงพยาบาลนาดูน',
    'โรงพยาบาลบรบือ',
    'โรงพยาบาลพยัคฆภูมิพิสัย',
    'โรงพยาบาลยางสีสุราช',
    'โรงพยาบาลวาปีปทุม',
    'โรงพยาบาลสุทธาเวช',
    'โรงพยาบาลร้อยเอ็ด',
    'โรงพยาบาลขอนแก่น',
    'โรงพยาบาลศรีนครินทร์'
];

export const GeneralInfoTab: React.FC<GeneralInfoTabProps> = ({ patient, onUpdate }) => {
    const [editSection, setEditSection] = useState<EditSection>(null);
    const [formData, setFormData] = useState<Patient>(patient);
    const [age, setAge] = useState({ years: '', months: '', days: '' });
    const [isDeceased, setIsDeceased] = useState(false);

    // Internal UI states for the selects
    const [selectedReferIn, setSelectedReferIn] = useState('');
    const [selectedReferOut, setSelectedReferOut] = useState('');

    useEffect(() => {
        if (editSection === null) {
            setFormData(patient);
        } else {
            if (!formData.referralType) {
                setFormData(prev => ({ ...prev, referralType: 'มหาสารคาม' }));
            }
            setAge(calculateAgeBreakdown(patient.dob));
            setIsDeceased(!!patient.deathDate);

            // Set select values based on raw data
            const rawIn = patient.referredFrom || '';
            setSelectedReferIn(rawIn === '' ? '' : (HOSPITALS.includes(rawIn) ? rawIn : 'อื่นๆ ระบุ'));

            const rawOut = patient.referOutLocation || '';
            setSelectedReferOut(rawOut === '' ? '' : (HOSPITALS.includes(rawOut) ? rawOut : 'อื่นๆ ระบุ'));
        }
    }, [patient, editSection]);

    // Auto-calculate status when relevant dates change in edit mode
    useEffect(() => {
        if (editSection !== null) {
            const computedStatus = calculatePatientStatus(formData);
            const newStatus = computedStatus || PatientStatus.ACTIVE;
            if (formData.status !== newStatus) {
                setFormData(prev => ({ ...prev, status: newStatus }));
            }
        }
    }, [formData.deathDate, formData.referOutDate, formData.nextAppointmentDate, editSection]);

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement> | { target: { name: string; value: string } }) => {
        const { name, value } = e.target;

        let updates: Partial<Patient> = { [name]: value };

        if (name === 'cid') {
            const numericValue = value.replace(/\D/g, '').slice(0, 13);
            updates.cid = numericValue;
        }

        if (name === 'title') {
            if (value === 'นาย') {
                updates.sex = 'ชาย';
            } else if (value === 'นาง' || value === 'นางสาว') {
                updates.sex = 'หญิง';
            }
        } else if (name === 'sex') {
            if (value === 'ชาย') {
                updates.title = 'นาย';
            } else if (value === 'หญิง') {
                if (formData.title === 'นาย') {
                    updates.title = 'นางสาว';
                }
            }
        } else if (name === 'referralType' && value === 'มหาสารคาม') {
            updates.referredFrom = '';
            updates.referralDate = undefined;
            setSelectedReferIn('');
        }

        setFormData(prev => ({ ...prev, ...updates }));
    };

    const handleHospitalSelectChange = (field: 'referredFrom' | 'referOutLocation', value: string) => {
        if (field === 'referredFrom') {
            setSelectedReferIn(value);
            if (value === 'อื่นๆ ระบุ') {
                setFormData(prev => ({ ...prev, referredFrom: '' }));
            } else if (value === '') {
                setFormData(prev => ({ ...prev, referredFrom: '' }));
            } else {
                setFormData(prev => ({ ...prev, referredFrom: value }));
            }
        } else {
            setSelectedReferOut(value);
            if (value === 'อื่นๆ ระบุ') {
                setFormData(prev => ({ ...prev, referOutLocation: '' }));
            } else if (value === '') {
                setFormData(prev => ({ ...prev, referOutLocation: '' }));
            } else {
                setFormData(prev => ({ ...prev, referOutLocation: value }));
            }
        }
    };

    const handleAddressSelectorChange = (key: 'subdistrict' | 'district' | 'province', value: string) => {
        setFormData(prev => ({ ...prev, [key]: value }));
    };

    const handleDobChange = (e: { target: { value: string } }) => {
        const val = e.target.value;
        setFormData(prev => ({ ...prev, dob: val }));
        setAge(calculateAgeBreakdown(val));
    };

    const handleAgeChange = (field: 'years' | 'months' | 'days', val: string) => {
        const newAge = { ...age, [field]: val };
        setAge(newAge);
        const dob = calculateDobFromAge(newAge.years, newAge.months, newAge.days);
        setFormData(prev => ({ ...prev, dob }));
    };

    const handleDeceasedChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const checked = e.target.checked;
        setIsDeceased(checked);
        if (!checked) {
            setFormData(prev => ({ ...prev, deathDate: undefined, causeOfDeath: undefined }));
        }
    };

    const handleSave = (e: React.FormEvent) => {
        e.preventDefault();
        if (formData.cid && formData.cid.length !== 13) {
            alert("เลขบัตรประชาชนต้องมี 13 หลัก");
            return;
        }
        onUpdate(formData);
        setEditSection(null);
    };

    const handleCancel = () => {
        setEditSection(null);
        setFormData(patient);
    };

    const currentCalculatedStatus = calculatePatientStatus(patient);
    const displayStatus = currentCalculatedStatus || '-';

    const SectionHeader = ({ title, section }: { title: string, section: EditSection }) => (
        <div className="flex justify-between items-center mb-6">
            <h3 className="text-lg font-semibold text-gray-800">{title}</h3>
            {editSection === null && (
                <button 
                    onClick={() => setEditSection(section)}
                    className="text-gray-400 hover:text-emerald-600 p-1 rounded-full hover:bg-emerald-50 transition-colors"
                    title="แก้ไขข้อมูล"
                >
                    <EditIcon className="w-4 h-4" />
                </button>
            )}
        </div>
    );

    const ActionButtons = () => (
        <div className="flex justify-end gap-4 mt-6 pt-4 border-t">
            <button type="button" onClick={handleCancel} className="px-4 py-2 text-sm font-medium text-gray-700 bg-white border border-gray-300 rounded-lg hover:bg-gray-50">
                ยกเลิก
            </button>
            <button type="submit" onClick={handleSave} className="px-4 py-2 text-sm font-medium text-white bg-emerald-600 rounded-lg hover:bg-emerald-700">
                บันทึก
            </button>
        </div>
    );

    return (
        <div className="space-y-6">
            {/* 1. Identification Section */}
            <div className="bg-white p-6 rounded-lg shadow-sm">
                <SectionHeader title="ข้อมูลระบุตัวตนผู้ป่วย (Patient Identification)" section="ID" />
                {editSection === 'ID' ? (
                    <form>
                        <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
                            <div>
                                <label htmlFor="hn" className={labelClass}>HN (Hospital Number)</label>
                                <input type="text" name="hn" id="hn" value={formData.hn} onChange={handleChange} className={inputClass} required />
                            </div>
                            <div>
                                <label htmlFor="cid" className={labelClass}>เลขบัตรประชาชน</label>
                                <input 
                                    type="text" 
                                    name="cid" 
                                    id="cid" 
                                    value={formData.cid || ''} 
                                    onChange={handleChange} 
                                    className={inputClass} 
                                    placeholder="13 หลัก"
                                    maxLength={13}
                                />
                            </div>
                            <div>
                                <label htmlFor="napId" className={labelClass}>NAP ID</label>
                                <input type="text" name="napId" id="napId" value={formData.napId} onChange={handleChange} className={inputClass} />
                            </div>
                             <div>
                                <label className={labelClass}>สถานะ (คำนวณอัตโนมัติ)</label>
                                <input 
                                    type="text" 
                                    disabled 
                                    value={calculatePatientStatus(formData) || '-'} 
                                    className={`${inputClass} bg-gray-100 text-gray-500 cursor-not-allowed`} 
                                />
                            </div>
                        </div>
                        <ActionButtons />
                    </form>
                ) : (
                    <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
                        <DisplayField label="HN (Hospital Number)" value={patient.hn} />
                        <DisplayField label="เลขบัตรประชาชน" value={patient.cid} />
                        <DisplayField label="NAP ID" value={patient.napId} />
                        <DisplayField label="สถานะ (ปัจจุบัน)" value={displayStatus} />
                    </div>
                )}
            </div>

            {/* 2. Demographic Section */}
            <div className="bg-white p-6 rounded-lg shadow-sm">
                <SectionHeader title="ข้อมูลประชากร (Demographic Information)" section="DEMO" />
                {editSection === 'DEMO' ? (
                    <form>
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                             <div>
                                <label htmlFor="title" className={labelClass}>คำนำหน้า</label>
                                <select name="title" id="title" value={formData.title} onChange={handleChange} className={inputClass}>
                                    <option value="">-- เลือก --</option>
                                    <option>นาย</option>
                                    <option>นาง</option>
                                    <option>นางสาว</option>
                                    <option>อื่นๆ</option>
                                </select>
                            </div>
                            <div>
                                <label htmlFor="firstName" className={labelClass}>ชื่อ</label>
                                <input type="text" name="firstName" id="firstName" value={formData.firstName} onChange={handleChange} className={inputClass} required />
                            </div>
                            <div>
                                <label htmlFor="lastName" className={labelClass}>นามสกุล</label>
                                <input type="text" name="lastName" id="lastName" value={formData.lastName} onChange={handleChange} className={inputClass} required />
                            </div>
                             <div>
                                <label htmlFor="dob" className={labelClass}>วันเกิด</label>
                                <DateInput name="dob" id="dob" value={formData.dob} onChange={handleDobChange} />
                            </div>
                            <div>
                                <label className={labelClass}>อายุ (คำนวณอัตโนมัติ)</label>
                                <div className="flex space-x-2 mt-1">
                                    <div className="flex-1 relative">
                                        <input 
                                            type="number" 
                                            min="0"
                                            placeholder="ปี" 
                                            value={age.years} 
                                            onChange={(e) => handleAgeChange('years', e.target.value)} 
                                            className="block w-full px-2 py-2 bg-white border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-emerald-500 focus:border-emerald-500 sm:text-sm" 
                                        />
                                        <span className="absolute right-2 top-2 text-xs text-gray-400">ปี</span>
                                    </div>
                                    <div className="flex-1 relative">
                                        <input 
                                            type="number" 
                                            min="0"
                                            max="11"
                                            placeholder="เดือน" 
                                            value={age.months} 
                                            onChange={(e) => handleAgeChange('months', e.target.value)} 
                                            className="block w-full px-2 py-2 bg-white border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-emerald-500 focus:border-emerald-500 sm:text-sm" 
                                        />
                                        <span className="absolute right-2 top-2 text-xs text-gray-400">ด</span>
                                    </div>
                                    <div className="flex-1 relative">
                                        <input 
                                            type="number" 
                                            min="0"
                                            max="31"
                                            placeholder="วัน" 
                                            value={age.days} 
                                            onChange={(e) => handleAgeChange('days', e.target.value)} 
                                            className="block w-full px-2 py-2 bg-white border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-emerald-500 focus:border-emerald-500 sm:text-sm" 
                                        />
                                        <span className="absolute right-2 top-2 text-xs text-gray-400">ว</span>
                                    </div>
                                </div>
                            </div>
                            <div>
                                <label htmlFor="sex" className={labelClass}>เพศ</label>
                                <select name="sex" id="sex" value={formData.sex} onChange={handleChange} className={inputClass}>
                                    <option value="">-- เลือก --</option>
                                    <option>ชาย</option>
                                    <option>หญิง</option>
                                </select>
                            </div>
                            <div>
                                <label htmlFor="occupation" className={labelClass}>อาชีพ/สถานศึกษา</label>
                                <input type="text" name="occupation" id="occupation" value={formData.occupation} onChange={handleChange} className={inputClass} />
                            </div>
                        </div>
                        <ActionButtons />
                    </form>
                ) : (
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                        <DisplayField label="คำนำหน้า" value={patient.title} />
                        <DisplayField label="ชื่อ" value={patient.firstName} />
                        <DisplayField label="นามสกุล" value={patient.lastName} />
                        <DisplayField label="วันเกิด" value={formatThaiDateBE(patient.dob || '')} />
                        <DisplayField label="เพศ" value={patient.sex} />
                        <DisplayField label="อาชีพ/สถานศึกษา" value={patient.occupation} />
                    </div>
                )}
            </div>

            {/* 3. Medical & Behavioral Section */}
            <div className="bg-white p-6 rounded-lg shadow-sm">
                <SectionHeader title="ข้อมูลทางการแพทย์และพฤติกรรม (Medical & Behavioral Information)" section="MED" />
                {editSection === 'MED' ? (
                    <form>
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                            <div>
                                <label htmlFor="partnerStatus" className={labelClass}>สถานะคู่นอน</label>
                                <select name="partnerStatus" id="partnerStatus" value={formData.partnerStatus} onChange={handleChange} className={inputClass}>
                                    <option value="">-- เลือก --</option>
                                    <option>ไม่มี</option>
                                    <option>มีคู่นอน</option>
                                </select>
                            </div>
                            <div>
                                <label htmlFor="partnerHivStatus" className={labelClass}>ผลเลือดของคู่นอน</label>
                                <select name="partnerHivStatus" id="partnerHivStatus" value={formData.partnerHivStatus} onChange={handleChange} className={inputClass}>
                                    <option value="">-- เลือก --</option>
                                    <option>ไม่ทราบ</option>
                                    <option>บวก (Positive)</option>
                                    <option>ลบ (Negative)</option>
                                </select>
                            </div>
                            <div>
                                <label htmlFor="riskBehavior" className={labelClass}>พฤติกรรมเสี่ยง</label>
                                <select name="riskBehavior" id="riskBehavior" value={formData.riskBehavior} onChange={handleChange} className={inputClass}>
                                    <option value="">-- เลือก --</option>
                                    <option value="MSM insertive">MSM insertive</option>
                                    <option value="MSM receptive">MSM receptive</option>
                                    <option value="MSM both">MSM both</option>
                                    <option value="Bisexual">Bisexual</option>
                                    <option value="Transgender">Transgender</option>
                                    <option value="Sex worker">Sex worker</option>
                                    <option value="IDU">IDU</option>
                                    <option value="Heterosexual">Heterosexual</option>
                                    <option value="Other">Other</option>
                                </select>
                            </div>
                        </div>
                        <ActionButtons />
                    </form>
                ) : (
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                        <DisplayField label="สถานะคู่นอน" value={patient.partnerStatus} />
                        <DisplayField label="ผลเลือดของคู่นอน" value={patient.partnerHivStatus} />
                        <DisplayField label="พฤติกรรมเสี่ยง" value={patient.riskBehavior} />
                    </div>
                )}
            </div>

            {/* 4. Contact & Eligibility Section */}
            <div className="bg-white p-6 rounded-lg shadow-sm">
                <SectionHeader title="ข้อมูลการติดต่อและสิทธิ์ (Contact & Eligibility)" section="CONTACT" />
                {editSection === 'CONTACT' ? (
                    <form>
                        <div className="grid grid-cols-1 gap-6">
                             {/* Thai Address Selector */}
                             <ThaiAddressSelector 
                                province={formData.province || ''}
                                district={formData.district || ''}
                                subdistrict={formData.subdistrict || ''}
                                onChange={handleAddressSelectorChange}
                            />

                            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                                <div className="md:col-span-3">
                                    <label htmlFor="address" className={labelClass}>ที่อยู่ (รายละเอียด)</label>
                                    <input type="text" name="address" id="address" value={formData.address} onChange={handleChange} className={inputClass} />
                                </div>
                                <div>
                                    <label htmlFor="phone" className={labelClass}>เบอร์โทรศัพท์</label>
                                    <input type="tel" name="phone" id="phone" value={formData.phone} onChange={handleChange} className={inputClass} />
                                </div>
                                <div>
                                    <label htmlFor="healthcareScheme" className={labelClass}>สิทธิการรักษา</label>
                                     <select name="healthcareScheme" id="healthcareScheme" value={formData.healthcareScheme} onChange={handleChange} className={inputClass}>
                                        <option value="">-- เลือก --</option>
                                        <option>บัตรทอง นอกเขต</option>
                                        <option>บัตรทอง ในเขต</option>
                                        <option>ประกันสังคม นอกเขต</option>
                                        <option>ประกันสังคม ในเขต</option>
                                        <option>จ่ายตรง กรมบัญชีกลาง</option>
                                        <option>จ่ายตรง ท้องถิ่น</option>
                                        <option>ชำระเงินเอง</option>
                                    </select>
                                </div>
                                 <div>
                                    <label htmlFor="nextAppointmentDate" className={labelClass}>วันนัดหมายครั้งถัดไป</label>
                                    <DateInput name="nextAppointmentDate" id="nextAppointmentDate" value={formData.nextAppointmentDate || ''} onChange={handleChange} />
                                </div>
                            </div>
                        </div>
                        <ActionButtons />
                    </form>
                ) : (
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                        <DisplayField label="จังหวัด" value={patient.province} />
